#include <OneWire.h>
#include <DallasTemperature.h>

#define ONE_WIRE_BUS 2
#define SSR_PIN 9
#define NTC_PIN A0
#define TEMP_CUTOFF 80.0f
#define SETPOINT 45.0f
#define CP_J_G 4.18f
#define MASS_G 500.0f

OneWire oneWire(ONE_WIRE_BUS);
DallasTemperature sensors(&oneWire);

float Kp=5.0f,Ki=0.12f,Kd=0.6f;
float intg=0,prevErr=0,cumHeat=0;
unsigned long lastTime=0,lastLog=0;

float readVesselTemp(){
  sensors.requestTemperatures();
  float s=0; int n=sensors.getDeviceCount();
  for(int i=0;i<n;i++) s+=sensors.getTempCByIndex(i);
  return n>0?s/n:25.0f;
}

float readJacketTemp(){
  int r=analogRead(NTC_PIN);
  float R=10000.0f*r/(1023.0f-r);
  return 1.0f/(log(R/10000.0f)/3950.0f+1.0f/298.15f)-273.15f;
}

void checkFault(float t){
  if(t>=TEMP_CUTOFF){
    analogWrite(SSR_PIN,255);
    Serial.println("FAULT:OVER_TEMP");
    while(1);
  }
}

int computePID(float sp,float pv){
  unsigned long now=millis();
  float dt=(now-lastTime)/1000.0f;
  if(dt<0.01f) dt=0.01f;
  float e=sp-pv;
  intg=constrain(intg+e*dt,-150.0f,150.0f);
  float d=(e-prevErr)/dt;
  prevErr=e; lastTime=now;
  return (int)constrain(Kp*e+Ki*intg+Kd*d,0,255);
}

void accumulateEnthalpy(float vT,float jT){
  float dT=vT-jT;
  float dQ=CP_J_G*MASS_G*dT/1000.0f;
  cumHeat+=dQ;
}

void logData(float vT,float jT,int pwm){
  if(millis()-lastLog<500) return;
  lastLog=millis();
  Serial.print(millis()); Serial.print(',');
  Serial.print(vT,2); Serial.print(',');
  Serial.print(jT,2); Serial.print(',');
  Serial.print(pwm); Serial.print(',');
  Serial.println(cumHeat,3);
}

void setup(){
  Serial.begin(115200);
  sensors.begin();
  pinMode(SSR_PIN,OUTPUT);
  lastTime=lastLog=millis();
  Serial.println("ms,vessel_T,jacket_T,pwm,cumH_kJ");
}

void loop(){
  float vT=readVesselTemp();
  float jT=readJacketTemp();
  checkFault(vT);
  int pwm=computePID(SETPOINT,vT);
  analogWrite(SSR_PIN,pwm);
  accumulateEnthalpy(vT,jT);
  logData(vT,jT,pwm);
  delay(200);
}
